import{c as a,Q as t,j as r,m as i}from"./chunks/framework.DVkeSyfh.js";const m=JSON.parse('{"title":"Smart Set Builder routing","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/smart-set-builder-routing.md","filePath":"concepts/smart-set-builder-routing.md","lastUpdated":null}'),s={name:"concepts/smart-set-builder-routing.md"};function o(n,e,d,l,c,u){return t(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="smart-set-builder-routing" tabindex="-1">Smart Set Builder routing <a class="header-anchor" href="#smart-set-builder-routing" aria-label="Permalink to &quot;Smart Set Builder routing&quot;">​</a></h1><p>Audience: users who want to understand SET output<br> Goal: explain seeds, anchors, BPM, diversity, and guards<br> Type: explanation</p><p>Smart Set Builder generates ordered previews. It is a route planner over local analysis data, not an automatic final set.</p><h2 id="candidate-requirements" tabindex="-1">Candidate requirements <a class="header-anchor" href="#candidate-requirements" aria-label="Permalink to &quot;Candidate requirements&quot;">​</a></h2><p>SET requires candidates with:</p><ul><li>SONARA features;</li><li>MERT embeddings;</li><li>MAEST embeddings;</li><li>CLAP audio embeddings.</li></ul><p>Tracks missing any required input are not feature-complete for SET.</p><h2 id="manual-seeds" tabindex="-1">Manual seeds <a class="header-anchor" href="#manual-seeds" aria-label="Permalink to &quot;Manual seeds&quot;">​</a></h2><p>Manual mode uses one to five selected seed tracks. Known artists must be unique among those seeds.</p><h2 id="auto-anchors" tabindex="-1">Auto anchors <a class="header-anchor" href="#auto-anchors" aria-label="Permalink to &quot;Auto anchors&quot;">​</a></h2><p>Auto mode samples the first anchor from the full feature-complete library, then samples remaining waypoint anchors from related candidates. The generated route bridges between those anchors.</p><h2 id="diversity-and-energy" tabindex="-1">Diversity and energy <a class="header-anchor" href="#diversity-and-energy" aria-label="Permalink to &quot;Diversity and energy&quot;">​</a></h2><p><code>Diversity</code> changes how broadly the route explores related candidates. <code>Energy curve</code> shapes the route as warmup, balanced, peak, or wave.</p><h2 id="bpm-modes" tabindex="-1">BPM modes <a class="header-anchor" href="#bpm-modes" aria-label="Permalink to &quot;BPM modes&quot;">​</a></h2><p><code>general</code> keeps normal transition compatibility. <code>low_to_high</code> and <code>high_to_low</code> add an actual-BPM trajectory with <code>slow</code>, <code>medium</code>, or <code>fast</code> change. Missing start or target BPM values can be inferred from the first seed/anchor and the library range.</p><p>Half/double tempo matching helps compatibility. It does not change the actual BPM trajectory.</p><h2 id="classifier-modifiers" tabindex="-1">Classifier modifiers <a class="header-anchor" href="#classifier-modifiers" aria-label="Permalink to &quot;Classifier modifiers&quot;">​</a></h2><p>Promoted classifiers are optional score modifiers. Missing scores stay neutral. Classifier flow can be flat, rise, or fall across the preview.</p><h2 id="artist-guard" tabindex="-1">Artist guard <a class="header-anchor" href="#artist-guard" aria-label="Permalink to &quot;Artist guard&quot;">​</a></h2><p>The generated preview keeps at most one track per known artist. Unknown artists cannot be guarded reliably, so clean metadata still matters.</p>',20)])])}const p=a(s,[["render",o]]);export{m as __pageData,p as default};
